class Solution {
    public double new21Game(int n, int k, int maxPts) {
        double[] dp = new double[n + 1];
        dp[0] = 1.0;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= Math.min(i, maxPts); j++) {
                dp[i] += dp[i - j] / maxPts;
            }
        }
        double res = 0;
        for (int i = k; i <= n; i++) {
            res += dp[i];
        }
        return res;
    }
}
